import java.io.*;
import java.util.*;

public class Main {
    static int[] solveCase(int n, int k, int[] snacks) {
        // your code here — return the N-K+1 distinct counts, leftmost window first
        return new int[n - k + 1];
    }

    public static void main(String[] args) throws IOException {
        StreamTokenizer in = new StreamTokenizer(new BufferedReader(new InputStreamReader(System.in)));
        in.nextToken();
        int t = (int) in.nval;
        StringBuilder out = new StringBuilder();
        while (t-- > 0) {
            in.nextToken(); int n = (int) in.nval;
            in.nextToken(); int k = (int) in.nval;
            int[] snacks = new int[n];
            for (int i = 0; i < n; i++) { in.nextToken(); snacks[i] = (int) in.nval; }
            int[] res = solveCase(n, k, snacks);
            for (int i = 0; i < res.length; i++) {
                out.append(res[i]);
                out.append(i + 1 < res.length ? ' ' : '\n');
            }
        }
        System.out.print(out);
    }
}

