    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t;
    cin >> t;
    while (t--) {
        int n, k;
        cin >> n >> k;
        vector<long long> snacks(n);
        for (auto& x : snacks) cin >> x;
        vector<int> res = solve_case(n, k, snacks);
        for (int i = 0; i < (int)res.size(); i++)
            cout << res[i] << (i + 1 < (int)res.size() ? ' ' : '\n');
    }
